/**
 * Notification model types.
 *
 * All notification channels (email, webhook, SMS, in-app, etc.) use these
 * shared types. The NotificationService routes notifications to the
 * appropriate adapter based on the channel.
 */

/**
 * Supported notification channels. New channels require a corresponding
 * NotificationAdapter implementation registered with the NotificationService.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in-app';

/**
 * Notification priority levels. Adapters may use priority to determine
 * delivery urgency (e.g., high-priority emails skip batching).
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * Categories of notifications. Used for user preference filtering
 * and routing logic.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_update'
  | 'system_alert';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}

/**
 * A persisted notification record.
 */
export interface NotificationRecord {
  id: string;
  payload: NotificationPayload;
  status: 'pending' | 'sent' | 'failed';
  sentAt?: Date;
  error?: string;
  createdAt: Date;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  error?: string;
}

/**
 * Base interface for all notification adapters.
 *
 * CONSTRAINT: Every notification channel (email, webhook, SMS, etc.) MUST
 * implement this interface. Adapters are registered with the NotificationService
 * by channel name. The service routes payloads to the correct adapter.
 *
 * Adapters should:
 * - Be stateless where possible (no shared mutable state between sends)
 * - Handle their own retries internally if needed
 * - Return a NotificationResult indicating success/failure
 * - Never throw — return { success: false, error: "..." } instead
 */

import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. Must be unique per service instance. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return a failure result instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel. Currently stores
 * sent emails in-memory for testing. Replace the send() body with a real
 * email provider (SMTP, SendGrid, SES, etc.) for production use.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

      const email: SentEmail = {
        to: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        sentAt: new Date(),
      };
      this.sentEmails.push(email);

      return { success: true };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /** Get all sent emails. Useful for testing. */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /** Clear sent emails. Useful for testing. */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — routes event-driven notifications to channel adapters.
 *
 * ARCHITECTURE: Event-driven via EventBus (unified pattern).
 *
 * All notifications flow through this pipeline:
 *   1. A service emits a domain event via EventBus.emit()
 *   2. This service's event handlers translate events into NotificationPayloads
 *   3. Payloads are routed to the appropriate NotificationAdapter by channel
 *   4. Adapters handle delivery (email, webhook, SMS, etc.)
 *
 * CONSTRAINTS:
 * - All notifications MUST go through EventBus.emit() — no direct calls
 * - All delivery channels MUST implement the NotificationAdapter interface
 * - Adapters are registered at construction time via registerAdapter()
 * - If no adapter is registered for a channel, the notification fails gracefully
 *
 * To add a new notification trigger:
 *   1. Define the event type in src/events/event-types.ts
 *   2. Add a handler in registerEventHandlers() that builds a NotificationPayload
 *   3. Call this.sendNotification(payload)
 *
 * To add a new delivery channel:
 *   1. Implement NotificationAdapter in src/adapters/
 *   2. Register it via notificationService.registerAdapter(adapter)
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationRecord,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: NotificationRecord[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is allowed; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that trigger notifications.
   * All event subscriptions are centralized here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.sendNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      channel: 'email',
      type: 'order_confirmation',
      priority: 'normal',
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.sendNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      channel: 'email',
      type: 'order_status_update',
      priority: 'normal',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * Records the result regardless of success or failure.
   */
  async sendNotification(payload: NotificationPayload): Promise<NotificationResult> {
    const adapter = this.adapters.get(payload.channel);
    const record: NotificationRecord = {
      id: generateNotificationId(),
      payload,
      status: 'pending',
      createdAt: new Date(),
    };

    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${payload.channel}`);
      record.status = 'failed';
      record.error = `No adapter for channel: ${payload.channel}`;
      this.notifications.push(record);
      return { success: false, error: record.error };
    }

    const result = await adapter.send(payload);

    if (result.success) {
      record.status = 'sent';
      record.sentAt = new Date();
      this.logger.info(`Notification sent: ${record.id} to ${payload.recipient} via ${payload.channel}`);
    } else {
      record.status = 'failed';
      record.error = result.error;
      this.logger.error(`Notification failed: ${record.id} — ${result.error}`);
    }

    this.notifications.push(record);
    return result;
  }

  /** Get all notification records. */
  getNotifications(): NotificationRecord[] {
    return [...this.notifications];
  }

  /** Get notifications for a specific recipient. */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.notifications.filter((n) => n.payload.recipient === recipient);
  }

  /** Get the count of sent notifications. */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /** Clear all notification records (useful for testing). */
  clearNotifications(): void {
    this.notifications = [];
  }
}

